const coaches = $('Supabase → Coach Data').all().map(i => i.json);
const report = $input.first().json.content?.[0]?.text || 'No report generated';

const topCoaches = coaches
  .filter(c => c.avg_rating >= 4.5)
  .map(c => ({ name: c.full_name, rating: c.avg_rating, lessons: c.total_lessons, city: c.city }));

const needsAttention = coaches
  .filter(c => c.avg_rating < 3.5 || c.active_students < 2)
  .map(c => ({ name: c.full_name, rating: c.avg_rating, active_students: c.active_students, city: c.city }));

return [{ json: {
  status: 'completed',
  workflow: '19_coach_performance',
  total_coaches: coaches.length,
  top_coaches: topCoaches,
  needs_attention: needsAttention,
  report,
  completedAt: new Date().toISOString()
} }];
